        "intent_api_call阶段状态为succeeded",
        "raw_response非空且可解析"
      ],
      "boundary": {"scope": "intent_api_call"},
      "priority": "critical",
      "evidence_refs": []
    },
    {
      "expectation_id": "意图标签为customer_portrait",
