        "extracted_output.intent == 'customer_portrait'"
      ],
      "boundary": {"scope": "adapter_extraction"},
      "priority": "critical",
      "evidence_refs": []
    },
    {
      "expectation_id": "置信度达到高可信水平",
      "downstream_consumer": "决策逻辑（如置信度阈值判定）",
      "user_intent": "客户画像分析",
      "expected_outcome": "返回的confidence值应>=0.85（或与参考值0.95接近）",
      "required_capabilities": ["意图识别模型置信度校准"],
      "acceptance_criteria": [
        "extracted_output.confidence >= 0.85"
      ],
      "boundary": {"scope": "adapter_extraction"},
      "priority": "high",
      "evidence_refs": []
    }
  ],
  "fulfillment_assessments": [
    {
      "expectation_id": "意图识别服务正常响应",
      "status": "not_fulfilled",
      "score": 0.0,
      "expected_evidence": ["intent_api_call success with raw_response"],
      "actual_evidence": ["intent_api_call failed: Connection refused"],
      "downstream_impact": "后续所有步骤无法获取意图，整个意图识别链路断裂",
      "blocking": true,
      "confidence": 1.0,
      "evidence_refs": [
        {
          "trace_stage": "intent_api_call",
          "status": "failed",
          "error": "Connection refused"
        }
      ]
    },
    {
      "expectation_id": "意图标签为customer_portrait",
      "status": "not_fulfilled",
      "score": 0.0,
      "expected_evidence": ["extracted intent = 'customer_portrait'"],
      "actual_evidence": ["label_mapping produced intent: null"],
      "downstream_impact": "无法进行客户画像相关的后续规划",
      "blocking": true,
      "confidence": 1.0,
      "evidence_refs": [
        {
          "trace_stage": "label_mapping",
          "intent": null
        }
      ]
    },
    {
      "expectation_id": "置信度达到高可信水平",
      "status": "not_fulfilled",
      "score": 0.0,
      "expected_evidence": ["confidence >= 0.85"],
      "actual_evidence": ["no confidence value available"],
      "downstream_impact": "缺少置信度，下游无法评估意图可靠性",
      "blocking": false,
      "confidence": 1.0,
      "evidence_refs": []
    }
  ],
  "overall_fulfillment": {
    "status": "not_fulfilled",
    "score": 0.0
  },
  "expected": {
    "intent": "customer_portrait",
    "confidence": 0.95
  },
  "missing": [
    {
      "kind": "intent_label",
      "error_type": "missing",
      "expected": "customer_portrait",
      "actual": null,
      "evidence_ref": "label_mapping",
      "raw": null,
      "incomplete": false
    },
    {
      "kind": "confidence",
      "error_type": "missing",
      "expected": 0.95,
      "actual": null,
      "evidence_ref": "label_mapping",
      "raw": null,
      "incomplete": false
    }
  ],
  "wrong": [],
  "extra": [],
  "evidence": [
    {
      "stage": "intent_api_call",
      "status": "failed",
      "error": "Connection refused",
      "evidence": {
        "endpoint": "/api/v1/marketing-planning/intent-recognition",
        "raw_response_present": false
      }
    },
    {
      "stage": "adapter_extraction",
      "status": "failed"
    },
    {
      "stage": "label_mapping",
      "status": "succeeded",
      "evidence": {
        "intent": null
      }
    }
  ],
  "reasoning_summary": "本次意图识别任务中，营销计划意图识别服务因连接被拒绝（Connection refused）而不可用，导致未返回任何有效响应。因此，期望的意图标签customer_portrait缺失（实际为null），置信度也缺失。所有关键业务期望均未满足，整体意图识别环节失败。"
}

